/// <summary>
/// To check InventLocation.KJPSMDomesticShipmentEnableFlag value
/// </summary>
[ExtensionOf(tableStr(InventLocation))]
internal final class KJP_SM_InventLocationTbl_Extension
{
}

Method.Source:
    /// <summary>
    /// To check InventLocation.KJPSMDomesticShipmentEnableFlag value
    /// </summary>
    /// <param name = "_inventLocationId">InventLocationId</param>
    /// <returns>boolean</returns>
    public boolean kjp_SM_checkDomesticShipmentEnableFlag(InventLocationId _inventLocationId)
    {
        InventLocation inventLocation;
        boolean        ret = false;

        select firstonly KJPSMDomesticShipmentEnableFlag, InventLocationId from inventLocation
            where inventLocation.InventLocationId == _inventLocationId;

        if (inventLocation.KJPSMDomesticShipmentEnableFlag)
        {
            ret = true;
        }
        return ret;
    }
